export const meta = { name: 'parallel_primality_synthesis', description: 'Run independent primality checks in parallel and synthesize surviving evidence.', phases: [{ title: 'Independent checks' }, { title: 'Synthesis' }] };

phase('Independent checks');
const checks = await parallel([
  () => agent('Check whether 17 is prime. Return a concise mathematical justification, and nothing else.', { model: 'sonnet' }),
  () => agent('Independently determine whether 17 is prime. Return a concise mathematical justification, and nothing else.', { model: 'sonnet' })
].map((run, index) => async () => {
  try {
    return { checker: index + 1, evidence: await run() };
  } catch (error) {
    return { checker: index + 1, failed: true, error: String(error?.message ?? error) };
  }
}));

const surviving = checks.filter(result => !result.failed);
const failedChecks = checks.filter(result => result.failed).map(result => result.checker);

phase('Synthesis');
const synthesis = await agent(`Synthesize the following surviving evidence about whether 17 is prime. Return ONLY valid compact JSON with exactly these keys: prime (boolean), evidence (array of strings), failedChecks (array of integers). Preserve failedChecks exactly.
Surviving evidence: ${JSON.stringify(surviving)}
Failed checker numbers: ${JSON.stringify(failedChecks)}`, { model: 'sonnet' });

let result;
try {
  result = JSON.parse(synthesis);
} catch {
  result = { prime: surviving.length > 0 && surviving.every(item => /prime/i.test(item.evidence)), evidence: surviving.map(item => item.evidence), failedChecks };
}
return result;

